import type { Metadata } from "next"

import { CrewSchedulingConsole } from "./console"

export const metadata: Metadata = {
    title: "乗員スケジュール管理 | 乗員部 クルースケジューリング",
    description:
        "乗務割（交番）・FTL（飛行時間制限）・資格／審査の期限を一画面で管理する乗員スケジューラー向けオペレーターコンソール。",
}

/**
 * 乗員スケジュール管理コンソール（Server Component shell）。
 *
 * The interactive console owns state + function props (cell `onSelect`,
 * `SignedRecord` render prop, `Meter` formatters), so it lives behind a
 * `"use client"` boundary — passing those from here would break `next build`.
 */
export default function CrewSchedulingPage() {
    return (
        <main className="min-h-full bg-background text-foreground">
            <CrewSchedulingConsole />
        </main>
    )
}

"use client"

import * as React from "react"
import {
    IconCalendarClock,
    IconClockHour4,
    IconLicense,
    IconUser,
} from "@tabler/icons-react"

import {
    ActionQueue,
    type ActionItem,
    Badge,
    Button,
    Card,
    CardContent,
    CardHeader,
    CardTitle,
    HStack,
    Meter,
    MetadataList,
    PageHeader,
    PersonCell,
    ReferenceValue,
    ScheduleGrid,
    type ScheduleAxisItem,
    type ScheduleCell,
    type ScheduleCellTone,
    Select,
    Separator,
    SignedRecord,
    type SignedRecordValue,
    StatGroup,
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger,
    Tag,
    Tooltip,
    TooltipContent,
    TooltipTrigger,
    VStack,
} from "@gunjo/ui"

import {
    CREW,
    type Crew,
    type CrewRole,
    currencyOf,
    type CurrencyStatus,
    DAYS,
    daysUntil,
    type Duty,
    type DutyKind,
    dutiesOf,
    KIND_LABEL,
    PERIOD_LABEL,
    type Qual,
    QUAL_KIND_LABEL,
    qualsOf,
    type QualKind,
    QUALS,
    ROLE_LABEL,
    TODAY,
} from "./data"

// ---------- presentation maps ----------

const ROLE_VARIANT: Record<CrewRole, "default" | "info" | "success" | "warning"> = {
    CAP: "info",
    "F/O": "info",
    CP: "success",
    CA: "default",
}

/** Map a duty kind → ScheduleGrid cell tone. A flagged cell overrides to destructive/warning. */
const KIND_TONE: Record<DutyKind, ScheduleCellTone> = {
    pairing: "primary",
    deadhead: "info",
    standby: "warning",
    briefing: "info",
    off: "muted",
    leave: "muted",
}

const CURRENCY: Record<
    CurrencyStatus,
    { label: string; variant: "success" | "warning" | "destructive" | "secondary" }
> = {
    valid: { label: "有効", variant: "success" },
    expiring: { label: "期限間近", variant: "warning" },
    lapsed: { label: "失効", variant: "destructive" },
    missing: { label: "未保有", variant: "destructive" },
}

function ftlFrac(c: Crew): number {
    return c.blockHours / c.blockLimit
}

// ---------- roster grid (central) ----------

function DutyCellBody({ duty }: { duty: Duty }) {
    const isWork = duty.kind === "pairing" || duty.kind === "deadhead"
    return (
        <div className="flex flex-col gap-0.5 leading-tight">
            <span className="text-[11px] font-semibold">
                {duty.code ?? KIND_LABEL[duty.kind]}
            </span>
            {duty.route ? (
                <span className="text-[10px] text-muted-foreground tabular-nums">{duty.route}</span>
            ) : (
                <span className="text-[10px] text-muted-foreground">{KIND_LABEL[duty.kind]}</span>
            )}
            <div className="mt-0.5 flex items-center gap-1">
                {isWork && duty.block ? (
                    <span className="text-[10px] tabular-nums text-muted-foreground">{duty.block}h</span>
                ) : null}
                {duty.confirmed ? (
                    <span className="text-[10px] font-medium text-success-strong">確定</span>
                ) : isWork ? (
                    <span className="text-[10px] font-medium text-warning">未確定</span>
                ) : null}
            </div>
        </div>
    )
}

const FLAG_NOTE: Record<NonNullable<Duty["flag"]>, string> = {
    ftl: "FTL（月間乗務時間上限）接近",
    rest: "最低休養（レスト）不足",
    qual: "必要資格を満たさないアサイン",
    understaffed: "スタンバイ不足",
}

// ---------- qualification currency matrix ----------

const QUAL_COLUMNS: QualKind[] = ["type", "route", "english", "check"]

function QualCellBody({ qual }: { qual: Qual }) {
    const status = currencyOf(qual)
    const meta = CURRENCY[status]
    const d = daysUntil(qual.expires)
    return (
        <div className="flex flex-col gap-1 leading-tight">
            <span className="text-[11px] font-medium">{qual.label}</span>
            <Badge variant={meta.variant} className="self-start">
                {meta.label}
            </Badge>
            <span className="text-[10px] text-muted-foreground tabular-nums">
                {qual.expires === null
                    ? status === "missing"
                        ? "—"
                        : "期限なし"
                    : `${qual.expires}${d !== null && d >= 0 ? `（残${d}日）` : d !== null ? `（${-d}日超過）` : ""}`}
            </span>
        </div>
    )
}

// ---------- main console ----------

export function CrewSchedulingConsole() {
    const [roleFilter, setRoleFilter] = React.useState<"all" | CrewRole>("all")
    const [selectedId, setSelectedId] = React.useState<string>(CREW[0].id)

    const visibleCrew = React.useMemo(
        () => (roleFilter === "all" ? CREW : CREW.filter((c) => c.role === roleFilter)),
        [roleFilter]
    )

    const selected = CREW.find((c) => c.id === selectedId) ?? CREW[0]

    // -------- roster ScheduleGrid model --------
    const rosterRows: ScheduleAxisItem[] = visibleCrew.map((c) => ({
        id: c.id,
        label: (
            <span className="flex flex-col items-center">
                <span className="text-[13px]">{c.name}</span>
                <span className="text-[10px] font-normal text-muted-foreground">{ROLE_LABEL[c.role]}</span>
            </span>
        ),
        ariaLabel: `${c.name} ${ROLE_LABEL[c.role]}`,
    }))

    const rosterColumns: ScheduleAxisItem[] = DAYS.map((d) => ({
        id: d.id,
        label: (
            <span className={d.isWeekend ? "text-destructive" : undefined}>
                {d.weekday}
            </span>
        ),
        sublabel: `${d.label}日`,
        ariaLabel: `${d.label}日（${d.weekday}）`,
    }))

    const rosterCells: ScheduleCell[] = visibleCrew.flatMap((c) =>
        dutiesOf(c.id).map((duty): ScheduleCell => {
            const tone: ScheduleCellTone = duty.flag ? "destructive" : KIND_TONE[duty.kind]
            const flagNote = duty.flag ? `／${FLAG_NOTE[duty.flag]}` : ""
            return {
                rowId: c.id,
                colId: duty.day,
                tone,
                content: <DutyCellBody duty={duty} />,
                description: `${KIND_LABEL[duty.kind]}${duty.code ? ` ${duty.code}` : ""}${
                    duty.route ? ` ${duty.route}` : ""
                }${flagNote}`,
                onSelect: () => setSelectedId(c.id),
            }
        })
    )

    // -------- qualification currency ScheduleGrid model --------
    const qualRows: ScheduleAxisItem[] = visibleCrew.map((c) => ({
        id: c.id,
        label: (
            <span className="flex flex-col items-center">
                <span className="text-[13px]">{c.name}</span>
                <span className="text-[10px] font-normal text-muted-foreground">{c.empNo}</span>
            </span>
        ),
        ariaLabel: `${c.name} ${c.empNo}`,
    }))

    const qualColumns: ScheduleAxisItem[] = QUAL_COLUMNS.map((k) => ({
        id: k,
        label: QUAL_KIND_LABEL[k],
    }))

    const qualCells: ScheduleCell[] = visibleCrew.flatMap((c) =>
        qualsOf(c.id).map((q): ScheduleCell => {
            const status = currencyOf(q)
            const tone: ScheduleCellTone =
                status === "lapsed" || status === "missing"
                    ? "destructive"
                    : status === "expiring"
                      ? "warning"
                      : "success"
            return {
                rowId: c.id,
                colId: q.kind,
                tone,
                content: <QualCellBody qual={q} />,
                description: `${q.label}・${CURRENCY[status].label}`,
                onSelect: () => setSelectedId(c.id),
            }
        })
    )

    // -------- 要対応 queue --------
    const actionItems: ActionItem[] = React.useMemo(() => buildActionQueue(), [])

    // -------- KPI strip --------
    const ftlNear = CREW.filter((c) => ftlFrac(c) >= 0.8).length
    const restShort = CREW.filter((c) => c.lastRestHours < c.minRestHours).length
    const qualProblems = QUALS.filter((q) => {
        const s = currencyOf(q)
        return s === "lapsed" || s === "expiring" || s === "missing"
    }).length
    const unconfirmed = CREW.flatMap((c) => dutiesOf(c.id)).filter(
        (d) => (d.kind === "pairing" || d.kind === "deadhead") && !d.confirmed
    ).length

    return (
        <div className="mx-auto flex w-full max-w-[1600px] flex-col gap-6 px-4 py-6">
            <PageHeader
                title="乗員スケジュール管理"
                subtitle={`乗務割・FTL・資格 — ${PERIOD_LABEL}`}
                sticky={false}
                actions={
                    <HStack gap={2} align="center">
                        <Select
                            aria-label="役職で絞り込み"
                            value={roleFilter}
                            onChange={(e) => setRoleFilter(e.target.value as "all" | CrewRole)}
                            className="w-44"
                        >
                            <option value="all">全乗員</option>
                            <option value="CAP">機長 (CAP)</option>
                            <option value="F/O">副操縦士 (F/O)</option>
                            <option value="CP">チーフパーサー (CP)</option>
                            <option value="CA">客室乗務員 (CA)</option>
                        </Select>
                        <Button variant="outline" size="sm">
                            公示前プレビュー
                        </Button>
                        <Button size="sm">乗務割を公示</Button>
                    </HStack>
                }
            />

            <StatGroup
                cols={{ base: 2, md: 4 }}
                items={[
                    {
                        label: "FTL接近（乗務時間≥80%）",
                        value: `${ftlNear}名`,
                        hint: "月間乗務時間上限に接近",
                        trend: ftlNear > 0 ? "up" : "flat",
                        tone: ftlNear > 0 ? "negative" : "neutral",
                    },
                    {
                        label: "レスト不足",
                        value: `${restShort}名`,
                        hint: "最低休養時間を下回る",
                        trend: restShort > 0 ? "up" : "flat",
                        tone: restShort > 0 ? "negative" : "neutral",
                    },
                    {
                        label: "資格の要対応",
                        value: `${qualProblems}件`,
                        hint: "失効・期限間近・未保有",
                        trend: "flat",
                        tone: qualProblems > 0 ? "negative" : "neutral",
                    },
                    {
                        label: "未確定の乗務指示",
                        value: `${unconfirmed}件`,
                        hint: "署名・確定待ち",
                        trend: "flat",
                        tone: unconfirmed > 0 ? "negative" : "positive",
                    },
                ]}
            />

            <div className="grid grid-cols-1 gap-6 xl:grid-cols-[minmax(0,1fr)_380px]">
                {/* LEFT: roster + qual matrix in tabs */}
                <div className="min-w-0">
                    <Tabs defaultValue="roster">
                        <TabsList>
                            <TabsTrigger value="roster">乗務割（交番）</TabsTrigger>
                            <TabsTrigger value="ftl">FTL・乗務時間</TabsTrigger>
                            <TabsTrigger value="quals">資格・審査</TabsTrigger>
                        </TabsList>

                        <TabsContent value="roster" className="px-0">
                            <RosterLegend />
                            <ScheduleGrid
                                label="乗員ローテーション（乗務割）"
                                cornerLabel="乗員 ＼ 日"
                                rows={rosterRows}
                                columns={rosterColumns}
                                cells={rosterCells}
                                rowHeaderWidth={108}
                                minColumnWidth={104}
                                className="mt-3"
                            />
                        </TabsContent>

                        <TabsContent value="ftl" className="px-0">
                            <FtlPanel crew={visibleCrew} onSelect={setSelectedId} selectedId={selectedId} />
                        </TabsContent>

                        <TabsContent value="quals" className="px-0">
                            <QualLegend />
                            <ScheduleGrid
                                label="資格・審査の期限（currency マトリクス）"
                                cornerLabel="乗員 ＼ 資格"
                                rows={qualRows}
                                columns={qualColumns}
                                cells={qualCells}
                                rowHeaderWidth={120}
                                minColumnWidth={150}
                                className="mt-3"
                            />
                        </TabsContent>
                    </Tabs>
                </div>

                {/* RIGHT: action queue + selected-crew detail */}
                <div className="flex min-w-0 flex-col gap-6">
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2 text-base">
                                <IconCalendarClock className="size-4" aria-hidden />
                                要対応キュー
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <ActionQueue items={actionItems} />
                        </CardContent>
                    </Card>

                    <CrewDetail crew={selected} />
                </div>
            </div>
        </div>
    )
}

// ---------- legends ----------

function RosterLegend() {
    const items: { label: string; tone: ScheduleCellTone }[] = [
        { label: "乗務（ペアリング）", tone: "primary" },
        { label: "デッドヘッド", tone: "info" },
        { label: "スタンバイ", tone: "warning" },
        { label: "公休／年休", tone: "muted" },
        { label: "要対応", tone: "destructive" },
    ]
    return (
        <HStack gap={2} wrap align="center" className="mt-2 text-xs text-muted-foreground">
            <span className="font-medium text-foreground">凡例</span>
            {items.map((it) => (
                <span key={it.label} className="inline-flex items-center gap-1.5">
                    <span className={"size-3 rounded-sm border " + LEGEND_SWATCH[it.tone]} aria-hidden />
                    {it.label}
                </span>
            ))}
        </HStack>
    )
}

function QualLegend() {
    return (
        <HStack gap={2} wrap align="center" className="mt-2">
            <span className="text-xs font-medium text-foreground">凡例</span>
            <Badge variant="success">有効</Badge>
            <Badge variant="warning">期限間近（30日以内）</Badge>
            <Badge variant="destructive">失効／未保有</Badge>
        </HStack>
    )
}

const LEGEND_SWATCH: Record<ScheduleCellTone, string> = {
    default: "bg-card border-border",
    muted: "bg-muted border-border",
    primary: "bg-primary/10 border-primary/40",
    info: "bg-info-subtle border-info-border",
    success: "bg-success-subtle border-success-border",
    warning: "bg-warning-subtle border-warning-border",
    destructive: "bg-destructive-subtle border-destructive",
}

// ---------- FTL panel ----------

function FtlPanel({
    crew,
    onSelect,
    selectedId,
}: {
    crew: Crew[]
    onSelect: (id: string) => void
    selectedId: string
}) {
    return (
        <Card className="mt-3">
            <CardHeader>
                <CardTitle className="flex items-center gap-2 text-base">
                    <IconClockHour4 className="size-4" aria-hidden />
                    FTL／乗務時間の消化状況（月間）
                </CardTitle>
            </CardHeader>
            <CardContent>
                <ul role="list" className="flex flex-col divide-y divide-border">
                    {crew.map((c) => {
                        const restShort = c.lastRestHours < c.minRestHours
                        return (
                            <li key={c.id} className="py-3 first:pt-0 last:pb-0">
                                <button
                                    type="button"
                                    onClick={() => onSelect(c.id)}
                                    aria-pressed={selectedId === c.id}
                                    className="flex w-full flex-col gap-2 rounded-md text-left outline-none focus-visible:ring-2 focus-visible:ring-ring"
                                >
                                    <HStack justify="between" align="center" gap={2}>
                                        <span className="flex items-center gap-2 text-sm font-medium">
                                            {c.name}
                                            <Badge variant={ROLE_VARIANT[c.role]}>{c.role}</Badge>
                                        </span>
                                        {restShort ? (
                                            <Badge variant="destructive">レスト不足 {c.lastRestHours}h</Badge>
                                        ) : (
                                            <span className="text-xs text-muted-foreground tabular-nums">
                                                直近レスト {c.lastRestHours}h
                                            </span>
                                        )}
                                    </HStack>
                                    <Meter
                                        label="乗務時間"
                                        value={c.blockHours}
                                        max={c.blockLimit}
                                        unit="h"
                                        thresholds={{ warning: 0.8, over: 1 }}
                                        size="sm"
                                    />
                                    <Meter
                                        label="勤務時間"
                                        value={c.dutyHours}
                                        max={c.dutyLimit}
                                        unit="h"
                                        thresholds={{ warning: 0.85, over: 1 }}
                                        size="sm"
                                    />
                                </button>
                            </li>
                        )
                    })}
                </ul>
            </CardContent>
        </Card>
    )
}

// ---------- selected-crew detail + sign-off ----------

function CrewDetail({ crew }: { crew: Crew }) {
    return (
        <Card>
            <CardHeader>
                <CardTitle className="flex items-center gap-2 text-base">
                    <IconUser className="size-4" aria-hidden />
                    乗員詳細
                </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
                <PersonCell
                    name={crew.name}
                    secondary={`${ROLE_LABEL[crew.role]}・${crew.empNo}`}
                    tertiary={`基地 ${crew.base}・${crew.types.join(" / ")}`}
                    presence={crew.presence}
                    presenceLabel="在席状況"
                    trailing={<Badge variant={ROLE_VARIANT[crew.role]}>{crew.role}</Badge>}
                />

                <Separator />

                <section aria-label="今月の乗務時間">
                    <h3 className="mb-2 text-xs font-semibold text-muted-foreground">今月の乗務時間</h3>
                    <Meter
                        label="乗務時間 (FTL)"
                        value={crew.blockHours}
                        max={crew.blockLimit}
                        unit="h"
                        thresholds={{ warning: 0.8, over: 1 }}
                    />
                    <div className="mt-2">
                        <Meter
                            label="勤務時間"
                            value={crew.dutyHours}
                            max={crew.dutyLimit}
                            unit="h"
                            thresholds={{ warning: 0.85, over: 1 }}
                        />
                    </div>
                    <div className="mt-3 flex items-center gap-2 text-sm">
                        <span className="text-muted-foreground">直近レスト</span>
                        <ReferenceValue
                            value={crew.lastRestHours}
                            range={{ low: crew.minRestHours }}
                            unit="h"
                            showLabel
                            labels={{ low: "最低休養を下回る" }}
                        />
                        <span className="text-xs text-muted-foreground">（最低 {crew.minRestHours}h）</span>
                    </div>
                </section>

                <Separator />

                <section aria-label="保有資格と期限">
                    <h3 className="mb-2 text-xs font-semibold text-muted-foreground">
                        <span className="inline-flex items-center gap-1.5">
                            <IconLicense className="size-3.5" aria-hidden />
                            保有資格と期限
                        </span>
                    </h3>
                    <MetadataList
                        layout="horizontal"
                        items={qualsOf(crew.id).map((q) => {
                            const status = currencyOf(q)
                            const meta = CURRENCY[status]
                            const d = daysUntil(q.expires)
                            return {
                                label: q.label,
                                value: (
                                    <span className="inline-flex items-center gap-2">
                                        <Badge variant={meta.variant}>{meta.label}</Badge>
                                        <span className="text-xs tabular-nums text-muted-foreground">
                                            {q.expires === null
                                                ? status === "missing"
                                                    ? "未保有"
                                                    : "期限なし"
                                                : `${q.expires}${
                                                      d !== null && d >= 0 ? `（残${d}日）` : ""
                                                  }`}
                                        </span>
                                    </span>
                                ),
                            }
                        })}
                    />
                </section>

                <Separator />

                <section aria-label="直近のアサイン">
                    <h3 className="mb-2 text-xs font-semibold text-muted-foreground">直近のアサイン</h3>
                    <VStack gap={1}>
                        {dutiesOf(crew.id)
                            .filter((d) => d.kind === "pairing" || d.kind === "deadhead")
                            .slice(0, 4)
                            .map((d, i) => (
                                <HStack key={i} justify="between" align="center" gap={2} className="text-sm">
                                    <span className="inline-flex items-center gap-2">
                                        <Tag variant="outline">{d.code}</Tag>
                                        <span className="text-xs text-muted-foreground tabular-nums">{d.route}</span>
                                    </span>
                                    <span className="text-xs text-muted-foreground tabular-nums">
                                        {d.day.slice(5)}
                                    </span>
                                </HStack>
                            ))}
                    </VStack>
                </section>

                <Separator />

                <section aria-label="乗務指示の確認">
                    <h3 className="mb-2 text-xs font-semibold text-muted-foreground">乗務指示 / 確認（署名）</h3>
                    <SignOff crew={crew} />
                </section>
            </CardContent>
        </Card>
    )
}

function SignOff({ crew }: { crew: Crew }) {
    // Per-crew sign-off record, reset when the selected crew changes (keyed below).
    const [record, setRecord] = React.useState<SignedRecordValue>({
        status: "draft",
        addenda: [],
    })

    const nextPairing = dutiesOf(crew.id).find((d) => d.kind === "pairing" && !d.confirmed)
    const blockingFlag = dutiesOf(crew.id).find((d) => d.flag)
    const canSign = !blockingFlag

    return (
        <SignedRecord
            value={record}
            onChange={setRecord}
            signerId="sched-石田"
            canSign={canSign}
            labels={{
                sign: "乗務指示を確定（署名）",
                draft: "未確定",
                signed: "確定済（ロック）",
                locked: "確定済の乗務指示は変更できません。修正は追記で行います。",
            }}
        >
            {({ readOnly }) => (
                <div className="rounded-md border border-border bg-muted/30 p-3 text-sm">
                    <p className="font-medium">
                        {crew.name}・{ROLE_LABEL[crew.role]} 乗務指示
                    </p>
                    <dl className="mt-1.5 grid grid-cols-[auto_1fr] gap-x-3 gap-y-0.5 text-xs">
                        <dt className="text-muted-foreground">期間</dt>
                        <dd className="tabular-nums">{PERIOD_LABEL}</dd>
                        <dt className="text-muted-foreground">次の乗務</dt>
                        <dd className="tabular-nums">
                            {nextPairing
                                ? `${nextPairing.code} ${nextPairing.route ?? ""}`
                                : "なし（未確定の乗務なし）"}
                        </dd>
                        <dt className="text-muted-foreground">ブリーフィング</dt>
                        <dd>出社後 60分前</dd>
                    </dl>
                    {!canSign && !readOnly ? (
                        <p className="mt-2 text-xs font-medium text-destructive">
                            ⚠ 未解消の要対応（{blockingFlag ? FLAG_NOTE[blockingFlag.flag!] : ""}）があるため確定できません。
                        </p>
                    ) : null}
                </div>
            )}
        </SignedRecord>
    )
}

// ---------- action queue model ----------

function buildActionQueue(): ActionItem[] {
    const items: ActionItem[] = []

    // FTL over / near
    for (const c of CREW) {
        const frac = ftlFrac(c)
        if (frac > 1) {
            items.push({
                id: `ftl-over-${c.id}`,
                severity: "critical",
                kind: "FTL超過",
                title: `${c.name}（${c.role}）月間乗務時間が上限超過`,
                detail: `乗務時間 ${c.blockHours}h / 上限 ${c.blockLimit}h — アサインを外す必要があります`,
                meta: `${Math.round(frac * 100)}%`,
                actions: (
                    <Tooltip>
                        <TooltipTrigger asChild>
                            <Button size="sm" variant="destructive">
                                再アサイン
                            </Button>
                        </TooltipTrigger>
                        <TooltipContent>超過分の乗務を別乗員へ振替</TooltipContent>
                    </Tooltip>
                ),
            })
        } else if (frac >= 0.8) {
            items.push({
                id: `ftl-near-${c.id}`,
                severity: "warning",
                kind: "FTL接近",
                title: `${c.name}（${c.role}）月間乗務時間が上限に接近`,
                detail: `乗務時間 ${c.blockHours}h / 上限 ${c.blockLimit}h`,
                meta: `${Math.round(frac * 100)}%`,
            })
        }
    }

    // rest shortfall
    for (const c of CREW) {
        if (c.lastRestHours < c.minRestHours) {
            items.push({
                id: `rest-${c.id}`,
                severity: "critical",
                kind: "レスト不足",
                title: `${c.name}（${c.role}）最低休養時間を下回る`,
                detail: `直近レスト ${c.lastRestHours}h（最低 ${c.minRestHours}h）— 次便前に休養確保が必要`,
                meta: `${c.lastRestHours}h`,
            })
        }
    }

    // qualification problems
    for (const q of QUALS) {
        const status = currencyOf(q)
        const crew = CREW.find((c) => c.id === q.crewId)!
        if (status === "lapsed") {
            items.push({
                id: `qual-lapsed-${q.crewId}-${q.kind}`,
                severity: "critical",
                kind: "資格失効",
                title: `${crew.name} ${q.label} が失効`,
                detail: "失効資格を要する便にアサインできません",
                meta: q.expires ?? "",
            })
        } else if (status === "missing") {
            items.push({
                id: `qual-missing-${q.crewId}-${q.kind}`,
                severity: "warning",
                kind: "資格未保有",
                title: `${crew.name} ${q.label} 未保有`,
                detail: "国際線ペアリングへのアサインに必要",
                meta: "未保有",
            })
        } else if (status === "expiring") {
            const d = daysUntil(q.expires)
            items.push({
                id: `qual-exp-${q.crewId}-${q.kind}`,
                severity: "warning",
                kind: "審査期限間近",
                title: `${crew.name} ${q.label} の期限が間近`,
                detail: "更新審査の手配が必要",
                meta: `残${d}日`,
            })
        }
    }

    // assignment violating qual (cell flag = "qual")
    for (const c of CREW) {
        const bad = dutiesOf(c.id).find((d) => d.flag === "qual")
        if (bad) {
            items.push({
                id: `assign-qual-${c.id}`,
                severity: "critical",
                kind: "不適合アサイン",
                title: `${c.name} 必要資格を満たさないアサイン`,
                detail: `${bad.code ?? ""} ${bad.route ?? ""} — 路線資格が未充足`,
                meta: bad.day.slice(5),
            })
        }
    }

    return items
}
